const supportCollectionId = String($supportCollectionId || '').trim();
const notificationEmail = String($notificationEmail || '').trim();
const urgentNotificationEmail = String($urgentNotificationEmail || '').trim();
const missing = [];
if (!supportCollectionId) missing.push('supportCollectionId');
if (!notificationEmail) missing.push('notificationEmail');
const guidance = [
  'Configuration required before this flow can create a support ticket.',
  missing.length ? `Missing startState keys: ${missing.join(', ')}` : '',
  '',
  'Required setup:',
  '1. Set startState.supportCollectionId to your Collections support ticket collection ID.',
  '2. Set startState.notificationEmail to the internal mailbox that should receive standard ticket notifications.',
  '3. Optional: Set startState.urgentNotificationEmail for high and critical issues.',
  '4. Connect a gmailOAuth2 credential on both Gmail nodes after import.'
].filter(Boolean).join('\n');
return {
  hasRequiredConfig: missing.length === 0,
  setupGuidance: guidance,
  normalizedSupportCollectionId: supportCollectionId,
  normalizedNotificationEmail: notificationEmail,
  normalizedUrgentNotificationEmail: urgentNotificationEmail
};

