inputs.customFunctionJavascriptFunction:
const clean = (value, fallback = '') => String(value ?? fallback).trim();
const normalizePriority = (value) => {
  const candidate = clean(value, 'normal').toLowerCase();
  if (['low', 'normal', 'high', 'critical'].includes(candidate)) return candidate;
  return 'normal';
};
const normalizeCategory = (value) => {
  const candidate = clean(value, 'other').toLowerCase();
  if (['bug', 'billing', 'access', 'feature_request', 'general_question', 'account', 'integration', 'other'].includes(candidate)) return candidate;
  return 'other';
};
const normalizeTeam = (value) => {
  const candidate = clean(value, clean($defaultAssigneeTeam, 'support')).toLowerCase();
  if (['support', 'product', 'engineering', 'billing', 'ops'].includes(candidate)) return candidate;
  return clean($defaultAssigneeTeam, 'support');
};
const createdAtIso = new Date().toISOString();
const datePart = createdAtIso.slice(0, 10).replace(/-/g, '');
const shortId = Math.random().toString(36).slice(2, 8).toUpperCase();
const ticketPrefix = clean($ticketPrefix, 'SUP').toUpperCase();
const ticketId = `${ticketPrefix}-${datePart}-${shortId}`;
const priority = normalizePriority(clean($triagePriority, $urgency || 'normal'));
const isUrgent = priority === 'high' || priority === 'critical';
const category = normalizeCategory($triageCategory);
const assignedTeam = normalizeTeam($triageSuggestedTeam);
const summary = clean($triageSummary, clean($subject, 'Support request'));
const nextAction = clean($triageNextAction, 'Review the ticket and contact the requester if more information is required.');
const standardNotificationEmail = clean($notificationEmail);
const urgentNotificationEmail = clean($urgentNotificationEmail);
const notificationTargetEmail = isUrgent ? (urgentNotificationEmail || standardNotificationEmail) : standardNotificationEmail;
const payload = {
  ticketId,
  createdAt: createdAtIso,
  status: clean($defaultStatus, 'new'),
  requesterName: clean($requesterName),
  requesterEmail: clean($requesterEmail),
  companyName: clean($companyName),
  subject: clean($subject),
  message: clean($message),
  urgency: normalizePriority(clean($urgency, 'normal')),
  category,
  priority,
  summary,
  assignedTeam,
  nextAction,
  referenceId: clean($referenceId),
  productArea: clean($productArea),
  preferredChannel: clean($preferredChannel),
  consentToContact: clean($consentToContact).toLowerCase() === 'true'
};
const notificationSubject = `[${priority.toUpperCase()}] ${ticketId} - ${clean($subject, 'Support request')}`;
const notificationBody = [
  `Ticket ID: ${ticketId}`,
  `Created At: ${createdAtIso}`,
  `Priority: ${priority}`,
  `Category: ${category}`,
  `Assigned Team: ${assignedTeam}`,
  `Requester: ${clean($requesterName)} <${clean($requesterEmail)}>` ,
  `Company: ${clean($companyName)}`,
  `Urgency (form): ${normalizePriority(clean($urgency, 'normal'))}`,
  `Reference ID: ${clean($referenceId)}`,
  `Product Area: ${clean($productArea)}`,
  `Preferred Channel: ${clean($preferredChannel)}`,
  '',
  'Summary:',
  summary,
  '',
  'Next Action:',
  nextAction,
  '',
  'Original Message:',
  clean($message)
].join('\n');
return {
  ticketId,
  createdAtIso,
  category,
  priority,
  assignedTeam,
  summary,
  nextAction,
  ticketRecordPayload: JSON.stringify(payload),
  notificationSubject,
  notificationBody,
  notificationTargetEmail,
  isUrgent
};

